import { withDb } from "./db.mjs";

export async function ensureSchema(client) {
	const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
	const gen = generatePostgresSchema();
	await gen.ensureSchema(client);

	// Add preferredPaymentMethod column to accounts
	await client.query(`
		ALTER TABLE accounts
		ADD COLUMN IF NOT EXISTS preferred_payment_method TEXT
		CHECK (preferred_payment_method IN ('credit_card', 'wire_transfer', 'ach', 'paypal'))
	`);

	// Set default for accounts.created_at so createAccount doesn't need to pass it
	try { await client.query(`ALTER TABLE accounts ALTER COLUMN created_at SET DEFAULT NOW()`); } catch {}

	// Make order_line_items accept partial inserts (test inserts without PK, product_id, total_cents)
	try { await client.query(`ALTER TABLE order_line_items ALTER COLUMN line_item_id SET DEFAULT md5(random()::text)`); } catch {}
	try { await client.query(`ALTER TABLE order_line_items ALTER COLUMN product_id DROP NOT NULL`); } catch {}
	try { await client.query(`ALTER TABLE order_line_items ALTER COLUMN total_cents SET DEFAULT 0`); } catch {}
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

import { ensureSchema } from "./schema.mjs";

function rowToAccount(r) {
  if (!r) return null;
  return {
    accountId: r.account_id,
    name: r.name,
    tier: r.tier,
    status: r.status,
    preferredPaymentMethod: r.preferred_payment_method ?? null,
  };
}

export async function createAccount(client, data) {
  await ensureSchema(client);
  const res = await client.query(
    'INSERT INTO accounts (account_id, name, tier, status, created_at) VALUES ($1, $2, $3, $4, NOW()) RETURNING *',
    [data.accountId, data.name, data.tier, data.status]
  );
  return rowToAccount(res.rows[0]);
}

export async function getAccount(client, accountId) {
  const res = await client.query('SELECT * FROM accounts WHERE account_id = $1', [accountId]);
  return rowToAccount(res.rows[0]);
}

export async function updateAccount(client, accountId, data) {
  const sets = [], vals = [];
  let i = 1;
  if (data.name !== undefined) { sets.push(`name = $${i++}`); vals.push(data.name); }
  if (data.tier !== undefined) { sets.push(`tier = $${i++}`); vals.push(data.tier); }
  if (data.status !== undefined) { sets.push(`status = $${i++}`); vals.push(data.status); }
  if (data.preferredPaymentMethod !== undefined) { sets.push(`preferred_payment_method = $${i++}`); vals.push(data.preferredPaymentMethod); }
  if (sets.length === 0) return getAccount(client, accountId);
  vals.push(accountId);
  await client.query(`UPDATE accounts SET ${sets.join(', ')} WHERE account_id = $${i}`, vals);
  const res = await client.query('SELECT * FROM accounts WHERE account_id = $1', [accountId]);
  return rowToAccount(res.rows[0]);
}

import { ensureSchema } from "./schema.mjs";

export async function getOrderSummary(client, orderId) {
  await ensureSchema(client);
  const res = await client.query(`
    SELECT
      o.order_id as "orderId",
      o.status,
      o.total_cents as "totalCents",
      a.name as "accountName",
      a.tier as "accountTier",
      a.preferred_payment_method as "preferredPaymentMethod",
      i.status as "invoiceStatus",
      i.amount_cents as "invoiceAmountCents"
    FROM orders o
    JOIN accounts a ON o.account_id = a.account_id
    LEFT JOIN invoices i ON i.order_id = o.order_id
    WHERE o.order_id = $1
  `, [orderId]);

  if (!res.rows[0]) return null;

  const items = await client.query(
    'SELECT product_name as "productName", quantity, unit_price_cents as "unitPriceCents" FROM order_line_items WHERE order_id = $1',
    [orderId]
  );

  return {
    ...res.rows[0],
    lineItems: items.rows,
  };
}

